class Solution:
    def longestPalindrome(self, s):
        best = ''
        def expand(l, r):
            nonlocal best
            while l >= 0 and r < len(s) and s[l] == s[r]:
                l -= 1; r += 1
            if r - l - 1 > len(best): best = s[l + 1:r]
        for i in range(len(s)):
            expand(i, i); expand(i, i + 1)
        return best
